(function($) {
 'use strict';
 
 var SearchWidget = {
 timer: null,
 minLength: 2,
 delay: 300,
 
 init: function() {
 this.form = $('#ajax-search-form');
 this.input = $('#search-keyword');
 this.results = $('#search-results');
 this.error = $('#search-error');
 this.csrf = $('#search-csrf');
 
 if (this.form.length === 0) {
 return;
 }
 
 this.bindEvents();
 },
 
 bindEvents: function() {
 var self = this;
 
 this.input.on('input', function() {
 clearTimeout(self.timer);
 var keyword = $(this).val().trim();
 
 if (keyword.length < self.minLength) {
 self.hideResults();
 return;
 }
 
 self.timer = setTimeout(function() {
 self.performSearch(keyword);
 }, self.delay);
 });
 
 this.form.on('submit', function(e) {
 e.preventDefault();
 var keyword = self.input.val().trim();
 
 if (keyword.length >= self.minLength) {
 self.performSearch(keyword);
 }
 });
 
 $(document).on('click', function(e) {
 if (!$(e.target).closest('.widget.search').length) {
 self.hideResults();
 }
 });
 },
 
 performSearch: function(keyword) {
 var self = this;
 
 this.showLoading();
 
 $.ajax({
 url: scriptlog_vars.api_url + '/search',
 type: 'GET',
 data: {
 q: keyword,
 type: 'all'
 },
 dataType: 'json',
 success: function(response) {
 if (response.success) {
 self.displayResults(response.data);
 } else {
 self.showError(response.message || 'Search failed');
 }
 },
 error: function(xhr, status, error) {
 var message = 'An error occurred during search: ' + error;
 try {
 var response = JSON.parse(xhr.responseText);
 if (response.message) {
 message = response.message;
 }
 if (response.error) {
 message += ' - ' + response.error;
 }
 } catch (e) {
 message += ' (Response: ' + xhr.responseText + ')';
 }
 self.showError(message);
 }
 });
 },
 
 displayResults: function(data) {
 this.hideError();
 
 if (!data.results || data.results.length === 0) {
 this.results.html(
 '<div class="search-no-results">' +
 'No results found for "<strong>' + this.escapeHtml(data.keyword) + '</strong>"' +
 '</div>'
 ).addClass('show');
 return;
 }
 
 var html = '<div class="search-result-count">Found ' + data.total + ' result(s)</div>';
 
 var self = this;
 $.each(data.results.slice(0, 10), function(index, item) {
 var typeLabel = item.type === 'page' ? 'Page' : 'Post';
 html += 
 '<div class="search-result-item">' +
 '<a href="' + self.escapeHtml(item.url) + '">' +
 '<div class="search-result-title">' + self.escapeHtml(item.title) + '</div>' +
 '<div class="search-result-excerpt">' + self.escapeHtml(item.excerpt) + '</div>' +
 '<div class="search-result-type">' + typeLabel + '</div>' +
 '</a>' +
 '</div>';
 });
 
 if (data.results.length > 10) {
 html += '<div class="search-result-item" style="text-align:center;">' +
 '<a href="' + scriptlog_vars.site_url + '/blog?q=' + encodeURIComponent(data.keyword) + '">View all ' + data.total + ' results</a>' +
 '</div>';
 }
 
 this.results.html(html).addClass('show');
 },
 
 showLoading: function() {
 this.results.html('<div class="search-loading"><i class="fa fa-spinner fa-spin"></i> Searching...</div>').addClass('show');
 },
 
 showError: function(message) {
 this.results.removeClass('show');
 this.error.text(message).addClass('show');
 },
 
 hideError: function() {
 this.error.removeClass('show').text('');
 },
 
 hideResults: function() {
 this.results.removeClass('show');
 },
 
 escapeHtml: function(text) {
 if (!text) return '';
 var div = document.createElement('div');
 div.textContent = text;
 return div.innerHTML;
 }
 };
 
 $(document).ready(function() {
 SearchWidget.init();
 });
 
})(jQuery);